import { useEffect, useState } from "react"
import API from "../services/api"
import { useNavigate } from "react-router-dom"
export default function SavedJobs() {

    const [savedJobs, setSavedJobs] =useState([])
    const navigate = useNavigate()

    useEffect(() => {

        const fetchJobs = async () => {

            try {

                const token =
                    localStorage.getItem("token")

                const res = await API.get(
                    "/profile/me",
                    {
                        headers: {
                            Authorization:
                                `Bearer ${token}`
                        }
                    }
                )

                setSavedJobs(
                    res.data.savedJobs || []
                )

            } catch (error) {

                console.log(error)
            }
        }

        fetchJobs()

    }, [])

    const handleDelete = async (role) => {

        try {

            const token =
                localStorage.getItem("token")

            await API.delete(
                `/jobs/saved/${encodeURIComponent(role)}`,
                {
                    headers: {
                        Authorization:
                            `Bearer ${token}`
                    }
                }
            )

            setSavedJobs(
                savedJobs.filter(
                    job => job !== role
                )
            )

        } catch (error) {

            console.log(error)
        }
    }

    return (

        <div
            style={{
                padding: "30px",
                background: "#f4f4f4",
                minHeight: "100vh"
            }}
        >

            <h1>Saved Jobs</h1>
            <button
                onClick={() => navigate("/dashboard")}
                style={{
                    padding: "10px 15px",
                    backgroundColor: "#4CAF50",
                    color: "white",
                    border: "none",
                    borderRadius: "5px",
                    cursor: "pointer",
                    marginBottom: "20px"
                }}
            >
                ← Back to Dashboard
            </button>

            {user.savedJobs.map((job, index) => (
    <div key={index}>
        <h3>{job.role}</h3>
        <p>Match Score: {job.matchScore}%</p>

        <p>
            Skills:
            {job.skills.join(", ")}
        </p>

        <small>
            Saved on:
            {" "}
            {new Date(job.savedAt).toLocaleDateString()}
        </small>
    </div>
))}

        </div>
    )
}
